// Run Once for All Items: пара (apartment, fetched_text) по индексу
function toIso(s){
  return s && s.length === 8
    ? s.slice(0,4) + '-' + s.slice(4,6) + '-' + s.slice(6,8)
    : s;
}
const apts    = $('Load Apartments For Sync').all().map(i => i.json);
const fetched = $input.all().map(i => i.json);
const out = [];
for (let k = 0; k < fetched.length; k++) {
  const apt = apts[k] || {};
  const text = (fetched[k] && fetched[k].data) || '';
  const aId = String(apt.id || '');
  const aName = String(apt.name || '');
  const lot = String(apt.lot || '');
  const events = [];
  if (text && text.length >= 20) {
    let cur = {};
    for (const line of text.split('\n')) {
      const s = line.trim();
      if (s === 'BEGIN:VEVENT') cur = {};
      else if (s.startsWith('DTSTART')) cur.start = toIso(s.split(':').pop().substring(0,8));
      else if (s.startsWith('DTEND'))   cur.end   = toIso(s.split(':').pop().substring(0,8));
      else if (s.startsWith('SUMMARY')) cur.summary = s.split(':').slice(1).join(':');
      else if (s === 'END:VEVENT' && cur.start && cur.end) {
        events.push({ ...cur, apartment_id: aId, apartment_name: aName, lot_id: lot });
      }
    }
  }
  out.push({ json: { events, count: events.length, apartment_id: aId, apartment_name: aName, lot_id: lot } });
}
return out;

// Run Once for All Items: разворачиваем events всех 4 квартир и дедуплицируем по id
const seen = new Map();
for (const it of $input.all()) {
  const events = (it.json && it.json.events) || [];
  for (const ev of events) {
    const key = String(ev.apartment_id) + '-' + ev.start;
    seen.set(key, ev); // последний выигрывает
  }
}
return Array.from(seen.values()).map(ev => ({ json: ev }));
